const fs = require('fs');
const path = require('path');

class ProblemsService {
  constructor() {
    this.problemsPath = path.resolve(__dirname, '../../data/problems.json');
    this.problems = null;
  }

  async loadProblems() {
    if (!this.problems) {
      const data = await fs.promises.readFile(this.problemsPath, 'utf8');
      this.problems = JSON.parse(data);
    }
    return this.problems;
  }

  async getProblemById(problemId) {
    const problems = await this.loadProblems();
    const problem = problems.find(p => p.problemId === problemId);
    if (!problem) {
      const error = new Error('Problem not found');
      error.status = 404;
      throw error;
    }
    return problem;
  }

  async getProblemDetails(problemId) {
    const problem = await this.getProblemById(problemId);

    // Aggregate componentStats
    const componentStats = problem.componentStats || [];

    const languages = {};
    const statusCounts = {};
    let maxPoints = 0;

    for (const comp of componentStats) {
      if (comp.language) {
        languages[comp.language] = (languages[comp.language] || 0) + 1;
      }
      if (comp.status) {
        statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
      }
      if (typeof comp.points === 'number' && comp.points > maxPoints) {
        maxPoints = comp.points;
      }
    }

    return {
      ...problem,
      componentStats: {
        languages,
        statusCounts,
        maxPoints,
      },
    };
  }
}

module.exports = new ProblemsService();
